import React, { useEffect, useState } from "react";
import axios from "axios";

const EventList = () => {
  const [events, setEvents] = useState([]);
  const [newEvent, setNewEvent] = useState({
    title: "",
    description: "",
    start_time: "",
    end_time: "",
  });
  const [showModal, setShowModal] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState(null); // Для редактирования
  const [alert, setAlert] = useState(null); // Для оповещений

  // Загрузка списка событий
  useEffect(() => {
    axios.get("http://localhost:8000/api/events/")
      .then(response => setEvents(response.data))
      .catch(error => console.error("Ошибка загрузки событий:", error));
  }, []);

  // Открытие модального окна для создания нового события
  const openCreateModal = () => {
    setSelectedEvent(null);  // Для сброса состояния перед созданием нового события
    setNewEvent({
      title: "",
      description: "",
      start_time: "",
      end_time: "",
    });
    setShowModal(true);      // Открытие модального окна
  };

  // Открытие модального окна для редактирования
  const openEditModal = (event) => {
    setSelectedEvent(event); // Устанавливаем событие для редактирования
    setNewEvent({
      title: event.title,
      description: event.description,
      start_time: new Date(event.start_time).toISOString().slice(0, 16), // Формат для поля datetime-local
      end_time: new Date(event.end_time).toISOString().slice(0, 16), // Формат для поля datetime-local
    });
    setShowModal(true);      // Открытие модального окна
  };

  // Обработчик создания и обновления события
  const handleCreateEvent = () => {
    const start_time = new Date(newEvent.start_time).toISOString().slice(0, 16); // Форматируем дату для отправки
    const end_time = new Date(newEvent.end_time).toISOString().slice(0, 16);   // Форматируем дату для отправки

    const eventData = { ...newEvent, start_time, end_time };

    if (selectedEvent) {
      // Обновляем существующее событие
      axios.put(`http://localhost:8000/api/events/${selectedEvent.id}/`, eventData)
        .then(response => {
          setEvents(events.map(event => event.id === selectedEvent.id ? response.data : event));
          setShowModal(false);
          setAlert({ message: "Мероприятие обновлено успешно!", type: "success" });
          setTimeout(() => setAlert(null), 3000);
        })
        .catch(error => {
          setAlert({ message: "Ошибка при обновлении мероприятия.", type: "danger" });
          setTimeout(() => setAlert(null), 3000);
        });
    } else {
      // Создаём новое событие
      axios.post("http://localhost:8000/api/events/", eventData)
        .then(response => {
          setEvents([...events, response.data]);
          setShowModal(false);
          setAlert({ message: "Мероприятие добавлено успешно!", type: "success" });
          setTimeout(() => setAlert(null), 3000);
        })
        .catch(error => {
          setAlert({ message: "Ошибка при создании мероприятия.", type: "danger" });
          setTimeout(() => setAlert(null), 3000);
        });
    }
  };

  // Удаление события
  const handleDeleteEvent = (id) => {
    axios.delete(`http://localhost:8000/api/events/${id}/`)
      .then(() => {
        setEvents(events.filter(event => event.id !== id));
        setAlert({ message: "Мероприятие удалено успешно!", type: "success" });
        setTimeout(() => setAlert(null), 3000);
      })
      .catch(error => {
        setAlert({ message: "Ошибка при удалении мероприятия.", type: "danger" });
        setTimeout(() => setAlert(null), 3000);
      });
  };

  return (
    <div>
      {/* Оповещения */}
      {alert && (
        <div className={`alert alert-${alert.type}`} role="alert">
          {alert.message}
        </div>
      )}

      <h1 className="text-center mb-4">Список мероприятий</h1>

      <button onClick={openCreateModal} className="btn btn-primary mb-3">
        Создать мероприятие
      </button>

      {/* Список карточек мероприятий */}
      <div className="row">
        {events.map(event => (
          <div key={event.id} className="col-md-4 mb-4">
            <div className="card">
              <div className="card-body">
                <h5 className="card-title">{event.title}</h5>
                <p className="card-text">{event.description}</p>
                <p className="card-text">
                  <small className="text-muted">Начало: {new Date(event.start_time).toLocaleString()}</small>
                </p>
                <button className="btn btn-warning" onClick={() => openEditModal(event)}>Редактировать</button>
                <button className="btn btn-danger ml-2" onClick={() => handleDeleteEvent(event.id)}>Удалить</button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Модальное окно для создания/редактирования мероприятия */}
      {showModal && (
        <div className="modal fade show" style={{ display: "block" }} tabIndex="-1" role="dialog">
          <div className="modal-dialog" role="document">
            <div className="modal-content">
              <div className="modal-header">
                <h5 className="modal-title">{selectedEvent ? "Редактировать мероприятие" : "Создать мероприятие"}</h5>
                <button type="button" className="close" data-dismiss="modal" aria-label="Close" onClick={() => setShowModal(false)}>
                  <span aria-hidden="true">&times;</span>
                </button>
              </div>
              <div className="modal-body">
                <form>
                  <div className="form-group">
                    <label htmlFor="title">Название</label>
                    <input
                      type="text"
                      className="form-control"
                      id="title"
                      name="title"
                      value={newEvent.title}
                      onChange={(e) => setNewEvent({ ...newEvent, title: e.target.value })}
                    />
                  </div>
                  <div className="form-group">
                    <label htmlFor="description">Описание</label>
                    <textarea
                      className="form-control"
                      id="description"
                      name="description"
                      value={newEvent.description}
                      onChange={(e) => setNewEvent({ ...newEvent, description: e.target.value })}
                    />
                  </div>
                  <div className="form-group">
                    <label htmlFor="start_time">Дата начала</label>
                    <input
                      type="datetime-local"
                      className="form-control"
                      id="start_time"
                      name="start_time"
                      value={newEvent.start_time}
                      onChange={(e) => setNewEvent({ ...newEvent, start_time: e.target.value })}
                    />
                  </div>
                  <div className="form-group">
                    <label htmlFor="end_time">Дата окончания</label>
                    <input
                      type="datetime-local"
                      className="form-control"
                      id="end_time"
                      name="end_time"
                      value={newEvent.end_time}
                      onChange={(e) => setNewEvent({ ...newEvent, end_time: e.target.value })}
                    />
                  </div>
                </form>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-secondary" onClick={() => setShowModal(false)}>Закрыть</button>
                <button type="button" className="btn btn-primary" onClick={handleCreateEvent}>
                  {selectedEvent ? "Обновить" : "Создать"}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default EventList;
